import React, { useEffect, useState } from "react";
import axios from "axios";
import { Line, Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

// Registrar los componentes de ChartJS
ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend
);

export default function Reportes() {
  const [ventasDia, setVentasDia] = useState([]);
  const [ventasMes, setVentasMes] = useState([]);

  useEffect(() => {
    obtenerVentasDia();
    obtenerVentasMes();
  }, []);

  const obtenerVentasDia = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/reportes/ventas/dia");
      setVentasDia(res.data);
    } catch (error) {
      console.error("❌ Error al obtener ventas por día:", error);
    }
  };

  const obtenerVentasMes = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/reportes/ventas/mes");
      setVentasMes(res.data);
    } catch (error) {
      console.error("❌ Error al obtener ventas por mes:", error);
    }
  };

  // Datos para gráficas
  const dataDia = {
    labels: ventasDia.map(v => v.Fecha),
    datasets: [
      {
        label: "Total Ingresos",
        data: ventasDia.map(v => v.TotalIngresos),
        borderColor: "rgba(75,192,192,1)",
        backgroundColor: "rgba(75,192,192,0.2)",
      },
    ],
  };

  const dataMes = {
    labels: ventasMes.map(v => `${v.Mes}/${v.Año}`),
    datasets: [
      {
        label: "Total Ingresos",
        data: ventasMes.map(v => v.TotalIngresos),
        backgroundColor: "rgba(153,102,255,0.6)",
      },
    ],
  };

  return (
    <div className="container mt-5">
      <h2 className="mb-4">📊 Reportes de Ventas</h2>

      <div className="mb-5">
        <h4>Ventas por Día</h4>
        <Line data={dataDia} />
      </div>

      <div className="mb-5">
        <h4>Ventas por Mes</h4>
        <Bar data={dataMes} />
      </div>
    </div>
  );
}
